+func loadConfig() (Config, error) {
+	cfg := baseConfig()
+	for _, path := range configPaths() {
+		if err := applyConfigFile(&cfg, path); err != nil {
+			return Config{}, err
+		}
+	}
+	applyEnv(&cfg)
+	if cfg.ServerType == "" {
+		cfg.ServerType = serverTypeForProviderClass(cfg.Provider, cfg.Class)
+	}
+	return cfg, nil
+}
